      "mainEntity": [
        {
          "@type": "Question",
          "name": "How to calculate room yield?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Room yield equals actual room revenue divided by the maximum potential room revenue, and it can also be read as occupancy multiplied by the achieved rate against rack rate. A 100 room hotel selling 2,170 room nights in a 31 day month at an average rate of Rs 4,500 earns Rs 97,65,000 against a potential Rs 1,39,50,000, a yield of 70 percent."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between occupancy rate, ADR and RevPAR?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Occupancy rate is room nights sold divided by room nights available, ADR is room revenue divided by rooms sold, and RevPAR is room revenue divided by rooms available, which equals occupancy times ADR. At 70 percent occupancy and an ADR of Rs 4,500, RevPAR is Rs 3,150. RevPAR is the single figure that captures both rate and volume."
          }
        },
        {
          "@type": "Question",
          "name": "How is GST on room tariff treated when measuring occupancy yield?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Yield is always computed on tariff net of GST, because the tax collected on a room night is a liability and not hotel revenue. The GST rate depends on the value of supply per unit per day, with a lower rate applying below the notified tariff threshold and the standard rate above it. Mixing gross and net tariffs across months distorts both ADR and RevPAR."
          }
        }
      ]
